import{_ as a,o as e,c as n,a2 as r}from"./chunks/framework.DZrHScmQ.js";const u=JSON.parse('{"title":"Context System","description":"","frontmatter":{},"headers":[],"relativePath":"ai-native/context-system/index.md","filePath":"ai-native/context-system/README.md"}'),l={name:"ai-native/context-system/index.md"};function s(i,t,o,d,c,h){return e(),n("div",null,[...t[0]||(t[0]=[r(`<h1 id="context-system" tabindex="-1">Context System <a class="header-anchor" href="#context-system" aria-label="Permalink to &quot;Context System&quot;">​</a></h1><p>上下文系统负责把真实工作中的证据转化为可检索记忆，再把反复验证的经验晋升为组织资产。</p><h2 id="核心判断" tabindex="-1">核心判断 <a class="header-anchor" href="#核心判断" aria-label="Permalink to &quot;核心判断&quot;">​</a></h2><p>Evolution Handbook 不是原始记忆池，而是经过审计的高密度知识层。</p><p>推荐分为四层：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>L0 Evidence       原始事实和工作产物</span></span>
<span class="line"><span>L1 Observations   有时间锚点的近期观察</span></span>
<span class="line"><span>L2 Reflections    合并、冲突分析和候选规律</span></span>
<span class="line"><span>L3 Standards      已采用的原则、契约、Skill 和 Playbook</span></span></code></pre></div><h2 id="层级职责" tabindex="-1">层级职责 <a class="header-anchor" href="#层级职责" aria-label="Permalink to &quot;层级职责&quot;">​</a></h2><table tabindex="0"><thead><tr><th>层级</th><th>内容</th><th>默认位置</th><th>加载方式</th></tr></thead><tbody><tr><td>L0</td><td>代码、PR、日志、会议记录、指标</td><td>原系统或项目仓库</td><td>按任务读取</td></tr><tr><td>L1</td><td>近期事实、状态和教训</td><td>私有 Context Workspace</td><td>检索后读取</td></tr><tr><td>L2</td><td>主题反思、候选模式和冲突</td><td>私有 Context Workspace</td><td>定期复审</td></tr><tr><td>L3</td><td>组织长期知识</td><td>Evolution Handbook</td><td>路由后按需读取</td></tr></tbody></table><h2 id="设计原则" tabindex="-1">设计原则 <a class="header-anchor" href="#设计原则" aria-label="Permalink to &quot;设计原则&quot;">​</a></h2><ul><li>Pull 优先：Agent 根据任务检索相关上下文，不把全部记忆推入 Prompt。</li><li>稀疏优先：默认加载索引和摘要，细节按需披露。</li><li>证据优先：每条长期规则应能追溯到真实案例。</li><li>晋升有门槛：一次事件不自动成为 Best Practice。</li><li>Observer 与 Reflector 隔离：记录事实和修改规则不能在同一阶段完成。</li><li>公私分离：公共方法与私密上下文不进入同一仓库。</li></ul><h2 id="参考来源" tabindex="-1">参考来源 <a class="header-anchor" href="#参考来源" aria-label="Permalink to &quot;参考来源&quot;">​</a></h2><p>本目录吸收过 <a href="https://github.com/grapeot/context-infrastructure" target="_blank" rel="noreferrer">context-infrastructure</a> 的部分机制：根级路由、规则/技能/记忆分层、Observer/Reflector 隔离、Pull 而非 Push、公私分离。只采用机制，不复制其个人工作区内容或运行时绑定。</p><h2 id="导航" tabindex="-1">导航 <a class="header-anchor" href="#导航" aria-label="Permalink to &quot;导航&quot;">​</a></h2><ul><li><a href="./memory-lifecycle.html">上下文生命周期</a></li><li><a href="./public-private-boundary.html">公共与私有边界</a></li><li><a href="./../playbooks/run-context-review.html">运行上下文复审</a></li></ul>`,14)])])}const b=a(l,[["render",s]]);export{u as __pageData,b as default};
